// Provide the homepage URL — the workflow discovers all key pages automatically
// Slug is auto-generated from the domain name
return [{
  json: {
    url: 'https://example.com'
  }
}];

const links = ($json.links || []);
const baseUrl = $('Set Config').first().json.url.replace(/\/$/, '');

// Parse hostname with regex — URL constructor not available in n8n sandbox
const hostnameMatch = baseUrl.match(/^https?:\/\/([^\/]+)/);
const hostname = hostnameMatch ? hostnameMatch[1] : baseUrl;
const domain = hostname.replace(/^www\./, '');
const slug = domain.replace(/\.[^.]+$/, '').replace(/[^a-z0-9]+/gi, '-').toLowerCase();

const SKIP = /\/(blog|post|article|news|press|legal|privacy|terms|sitemap|tag|category|feed|wp-|admin|login|404|cdn|assets|uploads|media)\b/i;
const KEEP = /\/(about|service|contact|menu|pricing|location|team|appointment|booking|offer|product|portfolio|gallery)\b/i;

const filtered = [baseUrl];

for (const link of links) {
  if (filtered.length >= 8) break;
  const clean = link.replace(/\/$/, '');
  if (clean === baseUrl) continue;
  if (SKIP.test(clean)) continue;
  if (/sitemap/i.test(clean) || clean.match(/\.[a-z]{2,4}$/i)) continue;
  const pathMatch = clean.match(/^https?:\/\/[^\/]+(\/.*)?$/);
  const path = pathMatch ? (pathMatch[1] || '/') : '/';
  const depth = path.split('/').filter(Boolean).length;
  if (depth <= 2 && (KEEP.test(clean) || depth === 1)) {
    filtered.push(clean);
  }
}

return [{ json: { filtered_urls: filtered, homepage: baseUrl, slug } }];

const data = $json.data || {};
const url = data.metadata?.sourceURL || '(unknown url)';
const title = data.metadata?.title || url;
const screenshot = data.screenshot || null;

// Strip data URI lines and map noise from markdown before passing to Claude
const rawMarkdown = data.markdown || '(no content scraped)';
const cleanedMarkdown = rawMarkdown
  .split('\n')
  .filter(line => !line.includes('data:image'))
  .filter(line => !line.includes('maps.googleapis.com'))
  .filter(line => !line.includes('maps.gstatic.com'))
  .filter(line => !line.includes('©2026 Google'))
  .join('\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// Extract real image URLs from original markdown before stripping
const imgRegex = /!\[.*?\]\((https?:\/\/[^)\s]+)\)/g;
const imageUrls = [];
let m;
while ((m = imgRegex.exec(rawMarkdown)) !== null) {
  const src = m[1];
  if (
    !src.endsWith('.svg') &&
    !src.includes('data:') &&
    !src.includes('pixel') &&
    !src.includes('track') &&
    !src.includes('maps.googleapis.com') &&
    !src.includes('maps.gstatic.com') &&
    !src.includes('google.com/maps')
  ) {
    imageUrls.push(src);
  }
}

return [{ json: { formatted: `--- PAGE: ${title} | URL: ${url} ---\n\n${cleanedMarkdown}`, image_urls: imageUrls, screenshot } }];

const items = $input.all();
const slug = $('Filter Key Pages').first().json.slug;
const combined = items.map(i => i.json.formatted).join('\n\n========\n\n');

// Get screenshot from homepage (first item that has one)
const screenshot = items.find(i => i.json.screenshot)?.json.screenshot || null;

// Deduplicate image URLs across all scraped pages
const seen = new Set();
const imageUrls = [];
for (const item of items) {
  for (const u of (item.json.image_urls || [])) {
    if (!seen.has(u)) { seen.add(u); imageUrls.push(u); }
  }
}

return [{ json: { combined_content: combined, slug, image_urls: imageUrls.slice(0, 20), screenshot } }];

const combinedContent = $json.combined_content;
const slug = $json.slug;
const screenshot = $json.screenshot || null;
const imageUrls = $json.image_urls || [];

const textPrompt = `You are analyzing a local business website to create a precise brand profile for a redesign. Study everything carefully and return ONLY valid JSON — no markdown, no code blocks, no explanation.

${screenshot ? 'A screenshot of the homepage is attached. Use it to identify the current color palette, visual style, and layout.' : ''}

Return this exact JSON structure:
{
  "business_name": "exact business name from the site",
  "tagline": "their tagline or slogan, or null",
  "business_type": "specific type e.g. 'mobile pet grooming spa', 'competitive dance studio', 'craft brewery'",
  "services": ["list", "of", "specific", "services"],
  "contact": {
    "phone": "phone number or null",
    "email": "email or null",
    "address": "full address or null"
  },
  "hours": "business hours as a string, or null",
  "target_audience": "specific description of who they serve — age, lifestyle, needs",
  "tone": "one of: friendly, professional, casual, corporate, rustic, playful, luxury, energetic",
  "colors": {
    "primary": "#hexcode — dominant brand color visible on the site, or best inference from content",
    "accent": "#hexcode — standout accent color, or null",
    "background": "#hexcode — main background color"
  },
  "font_style": "describe the typography: e.g. 'elegant serif', 'clean modern sans', 'bold display', 'handwritten script'",
  "aesthetic_notes": "honest assessment of what is visually dated or weak about the current site",
  "key_differentiators": "specific credentials, awards, years in business, or unique claims",
  "redesign_direction": "one confident sentence: specific tone, palette approach, and layout style for the redesign"
}

Scraped content:

${combinedContent}`;

let messages;
if (screenshot) {
  messages = [{
    role: 'user',
    content: [
      { type: 'image', source: { type: 'url', url: screenshot } },
      { type: 'text', text: textPrompt }
    ]
  }];
} else {
  messages = [{ role: 'user', content: textPrompt }];
}

const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 1500,
  messages
});

return [{ json: { requestBody, slug, image_urls: imageUrls, screenshot } }];
